#include <stdio.h>
#include <stdlib.h>
#include <time.h>

void log_error(FILE* logfile, const char* error_msg) {
    time_t now;
    time(&now);
    fprintf(logfile, "[%s] ERROR: %s\n", ctime(&now), error_msg);
}

int main() {
    FILE* logfile = fopen("error.log", "a");
    if (logfile == NULL) {
        fprintf(stderr, "Failed to open log file\n");
        return 1;
    }
    
    const char* user_input = "User provided error message with %s format";
    log_error(logfile, user_input);
    
    fclose(logfile);
    return 0;
}